package ru.rsreu.sovynhik.pract_03;import ru.rsreu.sovynhik.pract_03.config.Constants;import ru.rsreu.sovynhik.pract_03.model.*;import ru.rsreu.sovynhik.pract_03.repository.*;import ru.rsreu.sovynhik.pract_03.service.*;import ru.rsreu.sovynhik.pract_03.ui.ConsoleUI;import java.util.Scanner;public class SecuritySystemApplication {    public static void main(String[] args) {        Scanner scanner = new Scanner(System.in);        System.out.print("Введите количество пользователей: ");        int userCount = Integer.parseInt(scanner.nextLine());        System.out.print("Введите количество объектов: ");        int objectCount = Integer.parseInt(scanner.nextLine());        UserRepository userRepository = initializeUsers(userCount);        ObjectRepository objectRepository = initializeObjects(objectCount);        AccessMatrixRepository accessMatrixRepository = new AccessMatrixRepository();        AccessMatrixService accessMatrixService = new AccessMatrixService(                accessMatrixRepository, userRepository, objectRepository);        accessMatrixService.initializeMatrix();        AuthenticationService authenticationService = new AuthenticationService(userRepository);        AuthorizationService authorizationService = new AuthorizationService(accessMatrixService);        ConsoleUI ui = new ConsoleUI(authenticationService, accessMatrixService, authorizationService);        ui.start();    }    private static UserRepository initializeUsers(int count) {        UserRepository repository = new UserRepository();        repository.addUser(new User(Constants.ADMIN_NAME, true));        for (int i = 1; i < count; i++) {            repository.addUser(new User(Constants.USER_PREFIX + i, false));        }        return repository;    }    private static ObjectRepository initializeObjects(int count) {        ObjectRepository repository = new ObjectRepository();        for (int i = 1; i <= count; i++) {            repository.addObject(new SystemObject(i));        }        return repository;    }}